FROM json_populate_recordset(null::photos, '[{"id": 25817, "title": "Calle Miguel de Ara 1951", "description": "Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. \"Calle de Ara, (Miguel).\" Esta es una larga y estrecha calle que une la calle de San Pablo con la de Pignatelli. En la imagen, tramo de la calle Miguel de Ara desde la calle Basilio Boggiero hasta la calle de San Pablo, al fondo, con la iglesia de San Pablo iluminada por el sol.", "year": 1951, "year_from": 1951, "year_to": 1951, "era": "Anos 50", "zone": "CASCO HIST├ôRICO", "lat": 41.655334, "lng": -0.886051, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14886485159.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14886485159.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/14886485159/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 23903, "title": "XIX Centenario 1940", "description": "Sello conmemorativo publicado y circulado con motivo de la celebraci├│n oficial del \"XIX Centenario de la Virgen del Pilar\", con un dibujo centrado en el moderno aspecto del templo del Pilar tras el puente de Piedra y el r├¡o Ebro.", "year": 1940, "year_from": 1940, "year_to": 1940, "era": "Anos 40", "zone": "CASCO HIST├ôRICO", "lat": 41.656737, "lng": -0.878219, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49465471091.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49465471091.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/49465471091/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 22091, "title": "Santiago Ap├│stol c.1950", "description": "Estatua del Ap├│stol Santiago, obra del escultor Antonio Torres, en el taller de la calle de Florencio Jardiel, antes de ser colocada sobre la puerta Este de la bas├¡lica del Pilar de Zaragoza. La obra de remodelaci├│n de la fachada, dirigida por Teodoro R├¡os, fue inaugurada en 1952. Fuente visual: Im├ígenes de nuestras vidas. El Peri├│dico de Arag├│n, 2015.", "year": 1950, "year_from": 1950, "year_to": 1950, "era": "Anos 50", "zone": "CASCO HIST├ôRICO", "lat": 41.657097, "lng": -0.879518, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19154405196.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19154405196.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/19154405196/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 22485, "title": "El Pilar 1964", "description": "Vista a├®rea del Pilar y el Ebro desde el oeste. Fuente: Foto TAF. Revista Triunfo.", "year": 1964, "year_from": 1964, "year_to": 1964, "era": "Anos 60", "zone": "CASCO HIST├ôRICO", "lat": 41.657616, "lng": -0.878541, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40252493393.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40252493393.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/40252493393/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 21352, "title": "Plaza del Pilar c.1900", "description": "Imagen capturada en la plaza del Pilar y centrada en el concurrido ingreso bajo o principal al templo metropolitano. En primer t├®rmino, el empedrado pavimento del plaza lindero con la calle de Dami├ín Forment.", "year": 1900, "year_from": 1900, "year_to": 1900, "era": "Anos 1900", "zone": "CASCO HIST├ôRICO", "lat": 41.655974, "lng": -0.878219, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54636251689.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54636251689.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/54636251689/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 23285, "title": "Calle de Alfonso I 1891", "description": "La calle Alfonso, una de esas tradicionales y castizas calles de las de \"toda la vida\", fue abierta en la d├®cada de 1860, como otra imitaci├│n del Par├¡s del Segundo Imperio. Su prop├│sito era crear un marco esc├®nico ideal para la burgues├¡a de la ciudad, uniendo el Coso con la plaza del Pilar. Su apertura se hizo modificando y realineando el trazado de todas las calles previas, comenzando por la calle del antiguo Trenque del Arzobispo, y terminando con la calle del antiguo Mes├│n de los Navarros. Como suele ser habitual, comerciantes e inquilinos protestaron porque las obras significaban el fin del mundo y el colapso de la econom├¡a internacional (por este orden). Todas las calles transversales debieron acomodar en chafl├ín su encuentro con la nueva v├¡a, y la homogeneidad compositiva se impuso en las fachadas de la calle, en cuyos bajos se instal├│ la crema comercial de la ciudad: caf├®s, confiter├¡as, bazares, plater├¡as, sastres. Alfonso I se convirti├│ en sin├│nimo de paseo, compras. escaparate, chafardeo, cotilleo. \"Gan├│ la ciudad\" es lo que se suele decir cuando en efecto son los propietarios del suelo y los bancos los que se llevan la parte del le├│n. En la imagen, visi├│n en altura de la nov├¡sima calle Alfonso I desde las alturas de la bas├¡lica concatedral, que permite apreciar en perspectiva la pulcra rectitud del nuevo trazado de esta parte antigua de la ciudad. Al fondo, en el entronque con el Coso Alto, ins├│lita vista del palacio del marqu├®s de Campo Franco, entre el palacio de S├ístago (izquierda) y el palacio del conde Fuentes (derecha), antes de ser convertida en la sede del Banco de Arag├│n (inaugurado en 1917). Mucho m├ís al fondo, el nuevo y descomunal edificio de la Facultad de Medicina y Ciencias, que se inaugurar├í un par de a├▒os despu├®s. Y m├ís all├í no hay m├ís. Fuente visual: AHPZ, Estudio Coyne, c.1891", "year": 1891, "year_from": 1891, "year_to": 1891, "era": "Siglo XIX", "zone": "CASCO HIST├ôRICO", "lat": 41.655977, "lng": -0.879206, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14984794535.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14984794535.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/14984794535/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 23809, "title": "Plaza del Pilar 1930", "description": "\"Entrada principal al templo de Nuestra Se├▒ora del Pilar\". En la imagen, la \"Puerta Baja\", y aspecto parcial de la plaza del Pilar.", "year": 1930, "year_from": 1930, "year_to": 1930, "era": "Anos 30", "zone": "CASCO HIST├ôRICO", "lat": 41.656295, "lng": -0.87824, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15421894968.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15421894968.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/15421894968/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 24888, "title": "Pl. del Pilar 1949", "description": "AHPZ. Estudio Coyne. \"Obras del actual Ayuntamiento. Plaza de Nuestra Se├▒ora del Pilar. Remodelaci├│n de la fachada de la Catedral Bas├¡lica de Nuestra Se├▒ora del Pilar\".", "year": 1949, "year_from": 1949, "year_to": 1949, "era": "Anos 40", "zone": "CASCO HIST├ôRICO", "lat": 41.65608, "lng": -0.877876, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15021790335.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15021790335.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/15021790335/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 21915, "title": "Pasaje del Comercio c.1935", "description": "Imagen capturada en el claroscuro interior del Pasaje del Comercio, construido en 1882-1883 a instancias del marqu├®s de Ayerbe, propietario del nuevo inmueble que ocupaba toda esa manzana. Al fondo contrasta la luminosa entrada desde la plaza del Pilar, donde destacan sus jardines y uno de los quioscos que flanqueaban el ingreso a la Puerta Baja del templo.", "year": 1935, "year_from": 1935, "year_to": 1935, "era": "Anos 30", "zone": "CASCO HIST├ôRICO", "lat": 41.655887, "lng": -0.878745, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53206126035.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53206126035.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/53206126035/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 22704, "title": "Pl. del Pilar 1970", "description": "Zona oriental de la plaza del Pilar, en una vista capturada junto a la puerta Baja de la bas├¡lica y con el tel├│n de fondo de la plaza de la Seo. Los elementos decorativos, adem├ís de un ajardinado espacio al pie del monumento a Goya, conforman uno de los cambiantes montajes que han caracterizado este singular escenario urbano. A la derecha y en primer t├®rmino, mozos de reemplazo del antiguo Servicio Militar Obligatorio se dirigen al Pilar.", "year": 1970, "year_from": 1970, "year_to": 1970, "era": "Anos 70", "zone": "CASCO HIST├ôRICO", "lat": 41.655844, "lng": -0.877696, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27709802468.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27709802468.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/27709802468/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 23789, "title": "Calle del Pilar a├▒os 30", "description": "Calle del Pilar en los a├▒os 30, tras el derribo de la manzana que confrontaba con los inmuebles del lado de los impares. Fuente: Instant├íneas zaragozanas, 1982.", "year": 1930, "year_from": 1930, "year_to": 1939, "era": "Anos 30", "zone": "CASCO HIST├ôRICO", "lat": 41.655905, "lng": -0.877564, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14701157377.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14701157377.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/14701157377/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 23893, "title": "Plaza del Pilar 1988", "description": "Actuaci├│n de Jos├® Antonio Labordeta en la plaza del Pilar en 1988. Al fondo, edificio El Cicl├│n, bas├¡lica y templete de turismo. Fuente: Heraldo de Arag├│n.", "year": 1988, "year_from": 1988, "year_to": 1988, "era": "Anos 80", "zone": "CASCO HIST├ôRICO", "lat": 41.655473, "lng": -0.878111, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33741166695.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33741166695.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/33741166695/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 24873, "title": "Ayuntamiento c.1976", "description": "Edificio del Ayuntamiento, inaugurado en 1965 tras dos d├®cadas en construcci├│n, seg├║n proyecto de Alberto Acha, Mariano Nasarre y Ricardo Magdalena, en una escena nocturna. Adem├ís de la decoraci├│n encargada a Joaqu├¡n Herrero Pascual, lucen en la imagen, como ornato a├▒adido y en primer t├®rmino, decenas de veh├¡culos a motor aparcados en la plaza de la Independencia junto al Gobierno Civil, un ejemplo de su preponderancia en esta ├®poca.", "year": 1976, "year_from": 1976, "year_to": 1976, "era": "Anos 70", "zone": "CASCO HIST├ôRICO", "lat": 41.655887, "lng": -0.877445, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14725416809.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14725416809.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/14725416809/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 20969, "title": "Puerta de Toledo 1853", "description": "Xilograf├¡a, firmada por J.A. - Benedicto, del arco o puerta de Toledo. Ya hab├¡a sido derribada en 1842. Est├í basada en un dibujo a l├ípiz de Cecilio Pizarro y Librado. Fuente: Semanario Pintoresco Espa├▒ol, 1853.", "year": 1853, "year_from": 1853, "year_to": 1853, "era": "Siglo XIX", "zone": "CASCO HIST├ôRICO", "lat": 41.656616, "lng": -0.8822, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19070326531.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19070326531.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/19070326531/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 21591, "title": "Mercado Central c.1920", "description": "Vista de la plaza de Lanuza con el Mercado central a la izquierda y, al fondo, las construcciones en la actual calle de las Murallas Romanas. Fuente: Foto Jes├║s Corm├ín. AMZ.", "year": 1920, "year_from": 1920, "year_to": 1920, "era": "Anos 20", "zone": "CASCO HIST├ôRICO", "lat": 41.656295, "lng": -0.882555, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24822219241.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24822219241.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/24822219241/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 22471, "title": "Plaza Lanuza 1964", "description": "Esquina de la plaza de Lanuza con la calle de los Predicadores, a la derecha. Fuente: Foto Mar├¡n Chivite. Revista Triunfo.", "year": 1964, "year_from": 1964, "year_to": 1964, "era": "Anos 60", "zone": "CASCO HIST├ôRICO", "lat": 41.656814, "lng": -0.882682, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33341924478.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33341924478.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/33341924478/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 23802, "title": "Estudios folkl├│ricos 1965", "description": "Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 11/05/1965. \"Primera jornada de estudios folkl├│ricos aragoneses.\" En el programa, ponencias como \"La vivienda popular aragonesa\", o \"La cer├ímica aragonesa\", y actuaciones de grupos de Dance y Jota mostrando lo mejor de su repertorio en el Teatro Principal y la plaza del Pilar. Cerr├│ Antonio Beltr├ín con las conclusiones de las sesiones de estudio. En la imagen, uno de los grupos de Dance en pleno \"palotiau\", bajo la presidencia de la Cruz de los Ca├¡dos en la Cruzada de Liberaci├│n contra el comunismo, sita en la plaza del Pilar. San Juan de los Panetes, en tierra de penumbra.", "year": 1965, "year_from": 1965, "year_to": 1965, "era": "Anos 60", "zone": "CASCO HIST├ôRICO", "lat": 41.657087, "lng": -0.880646, "image_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15196109887.webp", "thumb_url": "https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15196109887.webp", "source": "https://www.flickr.com/photos/zaragozaantigua/15196109887/", "author": "Zaragoza Antigua (Flickr)", "rights": "Uso educativo", "tags": []}, {"id": 25390, "title": "Puerta de Toledo 1840", "description": "Dibujo de Valent├¡n Carderera de 1840 de la Puer